  ('elementary-64311456-moex-00695', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '兒童出養可歸屬於Kadushin所言的那一類兒童福利服務範圍？', '["替代性", "保護性", "補充性", "支持性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00696', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '聯合國於1989年11月通過「兒童權利公約」，具有四項普遍性的指導原則，下列何者不是該公約的指 導原則？', '["禁止差別待遇", "兒童最佳利益", "意見表達及參與權", "重視多元交織性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00697', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '兒童及少年福利與權益保障法第二章有關於身分權益之敘述，下列何者錯誤？', '["從事收出養媒合服務，以經主管機關許可之財團法人、公私立兒童及少年安置、教養機構（以下統稱 收出養媒合服務者）為限", "收出養媒合服務者從事收出養媒合服務，不得向收養人收取服務費用", "胎兒出生後七日內，接生人應將其出生之相關資料通報衛生主管機關備查", "父母對於兒童及少年出養之意見不一致，或一方所在不明時，父母之一方仍可向法院聲請認可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00698', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '兒童及少年福利與權益保障法第25、26、26之1條明定直轄市、縣（市）主管機關應辦理居家式托育服 務之管理、監督及輔導等相關事項。有關於居家式托育服務之敘述，下列何者錯誤？', '["居家式托育服務，指兒童由其三親等內親屬以外之人員，於居家環境中提供收費之托育服務", "居家式托育服務提供者應為成年", "直轄市、縣（市）主管機關為辦理居家式托育服務提供者之登記、管理、輔導、監督及檢查等事項， 應自行或委託相關專業機構、團體辦理", "曾犯家庭暴力罪，經緩起訴處分或有罪判決確定之日起，終身不得擔任居家式托育服務提供者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00699', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '兒童及少年福利與權益保障法第33條之1明定，觀光遊樂業園區所附設之公共停車場，應保留多少比例 的汽車停車位，作為孕婦、育有6歲以下兒童者之停車位？', '["1%", "2%", "5%", "10%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00700', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '兒童及少年性剝削防制條例第2條清楚定義所稱兒童或少年性剝削的行為，下列行為何者不包含在內？', '["任何打擾、警告、嘲弄或辱罵他人之言語、動作或製造使人心生畏怖情境之行為", "使兒童或少年坐檯陪酒或涉及色情之伴遊、伴唱、伴舞等行為", "拍攝、製造兒童或少年為性交或猥褻行為之圖畫、照片、影片、影帶、光碟、電子訊號或其他物品", "利用兒童或少年為性交、猥褻之行為，以供人觀覽"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00701', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '身心障礙者權益保障法中有關於支持服務的規定，下列何者正確？', '["身心障礙者搭乘國內大眾運輸工具，憑身心障礙證明，免費搭乘", "國內航空業者除民航主管機關所訂之安全因素外，不認同身心障礙者可單獨旅行，而特別要求應有陪 伴人共同飛行者，陪伴人應予半價優待", "身心障礙者進入收費之公營或公設民營風景區、康樂場所或文教設施，憑身心障礙證明應予半價優待", "新建公共建築物及活動場所，應規劃設置便於各類身心障礙者行動與使用之設施及設備。未符合規定 者，不得核發建築執照或對外開放使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00702', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '身心障礙者權益保障法中，有關於身心障礙者之鑑定報告與需求評估相關事項之敘述，下列何者錯誤？', '["辦理有關身心障礙鑑定服務必要之診察、診斷或檢查等項目之費用，應由直轄市、縣（市）衛生主管 機關編列預算支應", "身心障礙證明有效期間最長為八年", "各級政府應至少每五年舉辦身心障礙者之生活狀況、保健醫療、特殊教育、就業與訓練、交通及福利 等需求評估及服務調查研究，並應出版、公布調查研究結果", "中華民國一百零一年七月十一日前執永久效期身心障礙手冊者，直轄市、縣（市）主管機關得逕予換 發無註記有效期間之身心障礙證明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00703', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '關於性別工作平等法各條請假期間的薪資計算事宜之敘述，下列何者錯誤？', '["性別工作平等法第20條，受僱者於其家庭成員預防接種、發生嚴重之疾病或其他重大事故須親自照顧 時，得請家庭照顧假，全年以七日為限。家庭照顧假期間，薪資照給", "性別工作平等法第19條，受僱於僱用三十人以上雇主之受僱者，為撫育未滿三歲子女，得向雇主請求 每天減少工作時間一小時，減少之工作時間，不得請求報酬", "性別工作平等法第18條，子女未滿二歲須受僱者親自哺（集）乳者，除規定之休息時間外，雇主應每 日另給哺（集）乳時間六十分鐘，視為工作時間", "性別工作平等法第15條規定，受僱者於其配偶分娩時，雇主應給予陪產假五日。陪產假期間，薪資照給"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00704', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '關於性別工作平等法第16條，受僱者於育嬰留職停薪期間，原有的社會保險處理事宜之敘述，下列何者 錯誤？', '["得繼續參加原有之社會保險", "由雇主負擔之保險費，免予繳納", "原由受僱者負擔之保險費，得遞延三年繳納", "原由受僱者負擔之保險費，由中央主管機關補貼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
